import React, { useEffect, useState } from 'react'
import Header from './Header';
import { test_img } from '../assets/img';

export const Game = () => {
    const [imgWidth, setImgWidth] = useState(0)
    const [imgHeight, setImgHeight] = useState(0)

  return (
    <div className='flex flex-col h-screen'>
        <Header/>
        <div className='flex flex-1 w-full justify-center overflow-hidden'>
            <img src={test_img} className=' h-full object-contain'
            onLoad={
                (e) => {
                    setImgWidth(e.currentTarget.width)
                    setImgHeight(e.currentTarget.height)
                }
            }
            />
        </div>

        <TextBox d_width={imgWidth} d_height={imgHeight} text={"Hey there! I hope you’re having an amazing day! It’s really great to see you, and I just wanted to take a moment to say hello and send some positive energy your way. I hope everything is going well for you, whether you’re working on something exciting, relaxing, or just going about your day. If there’s anything new or interesting happening in your life, I’d love to hear all about it! Wishing you a fantastic day ahead—stay awesome and take care!"} speed={100}></TextBox>

    </div>
  )
}
const TextBox = ({d_height, d_width, name, text, speed}) => {

    const [currentText, setCurrentText] = useState("")    
    useEffect(() => {
        setCurrentText("")
        let index = 0;        
        const typingWord = setInterval(() => {
            if(index < text.length) {
                index++;
                // console.log(index);
                setCurrentText(text.slice(0, index));
                // console.log(text.slice(0, index));
                // console.log(currentText)
            }         
        }, speed)

        return () => clearInterval(typingWord); 
    }, [speed, text])

    useEffect(() => {
        console.log("Updated currentText:", currentText);

    }, [currentText]);

    return (
        <div
        className='fixed bottom-0 left-1/2 -translate-x-1/2'
        style={{
            width: `${d_width}px`,
            height: `${d_height/3}px`
        }}
        >
            <span className='text-5xl absolute ml-8 mt-0 mr-8 text-white z-50'>
                ???
            </span>
            <span className='text-5xl absolute ml-8 mt-16 mr-8 text-white z-50'
            style={{
                textShadow: `
                -1px -1px 0 black,  
                1px -1px 0 black,  
                -1px  1px 0 black,  
                1px  1px 0 black,  
                -1px  0px 0 black,  
                1px  0px 0 black,  
                0px -1px 0 black,  
                0px  1px 0 black
            ` }}
            >{currentText}</span>
            <div className="w-full h-full relative bg-[rgba(128,128,255,0.5)] blur-md"/>

        </div>
    )
}

export default Game;
